async (params, browser) => {
  // Search Google Flights
  await browser.open(`https://www.google.com/travel/flights?q=${params.from}+to+${params.to}`)

  // Wait for flight results
  await browser.waitForSelector('li.pIav2d', 20000)

  // Let page fully render
  await browser.wait(3000)

  // Scroll down to find price tracking toggle
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Enable price tracking
  const track_result = await browser.evaluate(`const trackToggle = document.querySelector('button[aria-label*="Track prices"], button[aria-label*="track prices"], div[data-flt-ve="track_prices"] button, button[jsaction*="track"], div[class*="track"] button[role="switch"], input[aria-label*="Track"]'); if (trackToggle) { const isAlreadyOn = trackToggle.getAttribute('aria-checked') === 'true' || trackToggle.getAttribute('aria-pressed') === 'true' || trackToggle.classList.contains('enabled'); if (!isAlreadyOn) { trackToggle.click(); return { action: 'enabled', message: 'Price tracking has been enabled for this route' }; } else { return { action: 'already_enabled', message: 'Price tracking was already enabled for this route' }; } } const allButtons = document.querySelectorAll('button, div[role="button"]'); for (const btn of allButtons) { const text = (btn.textContent || '').toLowerCase(); const label = (btn.getAttribute('aria-label') || '').toLowerCase(); if (text.includes('track') || label.includes('track')) { btn.click(); return { action: 'clicked_track_button', message: 'Clicked a tracking-related button' }; } } return { action: 'not_found', message: 'Could not find price tracking toggle. You may need to be signed into Google.' }`)

  // Wait for tracking to be confirmed
  await browser.wait(2000)

  // Check tracking confirmation
  const tracking_status = await browser.evaluate(`const confirmation = document.querySelector('div[class*="snackbar"], div[class*="toast"], div[role="alert"], div[class*="confirmation"]'); const priceInsight = document.querySelector('div.CQYfx, div[class*="price-insight"], div[class*="tip"]'); return { from: params.from, to: params.to, confirmation: confirmation ? confirmation.textContent.trim() : '', price_insight: priceInsight ? priceInsight.textContent.trim() : '', url: window.location.href }`)

  return tracking_status
}
